<span class="line"><span style="color:#F9E2AF;font-style:italic;">            None</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#F38BA8;"> self</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">system_prompt</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">clone</span><span style="color:#9399B2;">(),</span></span>
